 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges,
 47→    camera, stageSize,
 48→}) => {
 49→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 50→    const galaxyUserIdMap = useMemo(() => {
 51→        const map = new Map();
 52→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 53→        return map;
 54→    }, [galaxies]);
 55→
 56→    // Galaxy spiral visuals — positioned at animated galaxy coords
 57→    const galaxyVisuals = useMemo(() =>
 58→        galaxies?.map(g => ({
 59→            x: g.x,
 60→            y: g.y,
 61→            ...generateGalaxyData(g.userId),
 62→            color: getStarColor(g.userId),
 63→        })) || []
 64→    , [galaxies]);
 65→
 66→    // ── Compute every star's render position ─────────────────────────
 67→    // Stars follow their parent galaxy's displacement from hash→animated,
 68→    // plus an optional pull offset toward similar galaxy centroids.
 69→    const computedStarPositions = useMemo(() => {
 70→        const map = new Map();
 71→        for (const post of posts) {
 72→            const uid = post.users?.id ?? post.user_id;
 73→
 74→            // Galaxy displacement: how far the galaxy moved from hash to animated
 75→            const hashGal = userHomeCoords(uid);
 76→            const animGal = galaxyPositions?.get(uid);
 77→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 78→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 79→
 80→            // Star pull offset (Gravity B)
 81→            const pull = starPullOffsets?.get(post.id);
 82→
 83→            // Base position = original hash+spiral coords
 84→            const baseX = post.universe_x ?? post.display_x;
 85→            const baseY = post.universe_y ?? post.display_y;
 86→
 87→            map.set(post.id, {
 88→                x: baseX + galDx + (pull?.dx ?? 0),
 89→                y: baseY + galDy + (pull?.dy ?? 0),
 90→            });
 91→        }
 92→        return map;
 93→    }, [posts, galaxyPositions, starPullOffsets]);
 94→
 95→    // ── Viewport culling: only render stars within visible bounds + buffer ──
 96→    const visibleBounds = useMemo(() => {
 97→        if (!camera || !stageSize || !zoom) return null;
 98→        const halfW = (stageSize.width / 2) / zoom;
 99→        const halfH = (stageSize.height / 2) / zoom;
100→        const bufferWorld = 500 / zoom;
101→        return {
102→            minX: camera.x - halfW - bufferWorld,
103→            maxX: camera.x + halfW + bufferWorld,
104→            minY: camera.y - halfH - bufferWorld,
105→            maxY: camera.y + halfH + bufferWorld,
106→        };
107→    }, [camera, stageSize, zoom]);
108→
109→    const visiblePosts = useMemo(() => {
110→        if (!visibleBounds) return posts; // fallback: render all
111→        return posts.filter(post => {
112→            const pos = computedStarPositions.get(post.id);
113→            if (!pos) return true; // keep if no position computed yet
114→            return pos.x >= visibleBounds.minX && pos.x <= visibleBounds.maxX
115→                && pos.y >= visibleBounds.minY && pos.y <= visibleBounds.maxY;
116→        });
117→    }, [posts, computedStarPositions, visibleBounds]);
118→
119→    const bridgePairs = useMemo(() => {
120→        const maxPairs = 120;
121→
122→        if (useEmbeddingBridges) {
123→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
124→                ? posts.filter((post) => activePostIds.has(post?.id))
125→                : posts;
126→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
127→        }
128→
129→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
130→
131→        return similarPairs
132→            .filter((pair) => Number(pair?.similarity) > 0.9)
133→            .filter((pair) => {
134→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
135→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
136→            })
137→            .slice(0, maxPairs);
138→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
139→
140→    return (
141→        <Layer {...layerProps}>
142→            {/* Semantic bridges between similar posts */}
143→            {bridgePairs.length > 0 && (
144→                <Shape
145→                    sceneFunc={(ctx) => {
146→                        for (const pair of bridgePairs) {
147→                            const posA = computedStarPositions.get(pair.post_a);
148→                            const posB = computedStarPositions.get(pair.post_b);
149→                            if (!posA || !posB) continue;
150→
151→                            const dx = posB.x - posA.x;
152→                            const dy = posB.y - posA.y;
153→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
154→
155→                            const mx = (posA.x + posB.x) / 2;
156→                            const my = (posA.y + posB.y) / 2;
157→                            const perpX = (-dy / dist) * dist * 0.06;
158→                            const perpY = (dx / dist) * dist * 0.06;
159→
160→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
161→                            ctx.lineWidth = 0.8;
162→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
163→                            ctx.shadowBlur = 4;
164→                            ctx.beginPath();
165→                            ctx.moveTo(posA.x, posA.y);
166→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
167→                            ctx.stroke();
168→                        }
169→                        ctx.shadowBlur = 0;
170→                    }}
171→                    perfectDrawEnabled={false}
172→                    listening={false}
173→                />
174→            )}
175→            {/* Spiral galaxy visuals + connection lines */}
176→            <Shape
177→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
178→                perfectDrawEnabled={false}
179→                listening={false}
180→            />
181→            {/* Galaxy name labels */}
182→            {galaxies?.map((g) => (
183→                <GalaxyLabel
184→                    key={g.userId}
185→                    x={g.x}
186→                    y={g.y}
187→                    name={g.name}
188→                    zoom={zoom}
189→                    onClick={() => onGalaxyClick(g)}
190→                />
191→            ))}
192→            {/* Stars (viewport-culled) */}
193→            {visiblePosts.map((post) => {
194→                const postUserId = post.users?.id ?? post.user_id;
195→                const color = getStarColor(postUserId);
196→                const likeCount = post.like_count != null
197→                    ? post.like_count
198→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
199→                const radius = getStarRadius(likeCount);
200→
201→                const pos = computedStarPositions.get(post.id);
202→                const x = pos?.x ?? post.universe_x ?? post.display_x;
203→                const y = pos?.y ?? post.universe_y ?? post.display_y;
204→
205→                return (
206→                    <StarGroup
207→                        key={post.id}
208→                        x={x}
209→                        y={y}
210→                        radius={radius}
211→                        color={color}
212→                        title={post.title}
213→                        showTitle={showTitles}
214→                        isPulsing={pulsingId === post.id}
215→                        onClick={() => onStarClick(post)}
216→                    />
217→                );
218→            })}
219→        </Layer>
220→    );
221→});
222→
223→InteractiveLayer.displayName = 'InteractiveLayer';
224→
225→export default InteractiveLayer;
