 235→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 72){
 236→        throw new Error('limit should be an integer between 1 and 72');
 237→    }
 238→
 239→    const normalizedSort = typeof sort === 'string' && sort.trim().toLowerCase() === 'newest'
 240→        ? 'newest'
 241→        : 'hottest';
 242→
 243→    let url = `${BASE_URL}/journals/canvas/gallery?limit=${parsedLimit}&sort=${encodeURIComponent(normalizedSort)}`;
 244→    if(userId){
 245→        url += `&userId=${encodeURIComponent(userId)}`;
 246→    }
 247→    if(cursor){
 248→        url += `&cursor=${encodeURIComponent(cursor)}`;
 249→    }
 250→
 251→    const response = await apiRequest(url, {
 252→        method: 'GET'
 253→    });
 254→
 255→    if(!response.ok){
 256→        const error = await response.json().catch(() => ({}));
 257→        throw new Error(error?.error || 'failed to fetch canvas gallery');
 258→    }
 259→
 260→    return await response.json();
 261→}
