  80→export const imageUploader = async(file, userId, bucket) =>{
  81→    if(!file){
  82→        return res.status(500).json({error: 'no file received'});
  83→    }
  84→
  85→    let img_buffer = null
  86→    let img_url = null
  87→    img_buffer = await sharp(file.buffer)
  88→    .webp({quality: 80})
  89→    .toBuffer();
  90→
  91→    const folderName = `user_id_${userId}`;
  92→    const fileName = `${Date.now()}_${crypto.randomUUID()}.webp`;
  93→    const filePath = `${folderName}/${fileName}`;
  94→
  95→    const {data: uploadImage, error: errorUploadImage} = await supabase.storage
  96→    .from(bucket)
  97→    .upload(filePath, img_buffer, {
  98→        contentType: 'image/webp',
  99→        upsert: true
 100→    })
 101→    if(errorUploadImage){
 102→        console.error('supabase error while uploading image to supabase bucket', errorUploadImage)
 103→        return res.status(500).json({error: 'error uploading image into supabase bucket'});
 104→    }
 105→    const {data: data_url} = supabase.storage
 106→    .from(bucket)
 107→    .getPublicUrl(filePath)
 108→    
 109→    if(data_url){
 110→        img_url = data_url.publicUrl;
