238→export const addFollowsService = async(followerId, followingId) => {
239→    if(!followerId || !followingId){
240→        console.error('followerId or followingId is undefined');
241→        throw {status: 400, error: 'followerId or followingId is undefined'};
242→    }
243→
244→    const {data: existing, error: errorExisting} = await supabase
245→    .from('follows')
246→    .select('*')
247→    .eq('follower_id', followerId)
248→    .eq('following_id', followingId)
249→    .maybeSingle();
250→
251→    if(errorExisting){
252→        console.error('supabase error while checking existing following:', errorExisting.message);
253→        throw {status: 500, error: 'supabase error while checking existing following'}
254→    }
255→
256→    if(existing){
257→        const {data: removeData, error: errorRemoveData} = await supabase
258→        .from('follows')
259→        .delete()
260→        .eq('follower_id', followerId)
261→        .eq('following_id', followingId)
262→
263→        if(errorRemoveData){
264→            console.error('supabase error while deleting follow data:', errorRemoveData.message);
265→            throw {status: 500, error: 'supabase error while deleting follow data'};
266→        }
267→
268→        return {message: 'deleted follows data'};
269→    } else {
270→        const data = {
271→            follower_id: followerId,
272→            following_id: followingId,
273→        }
274→
275→        const {data: inserData,  error: errorInserData} = await supabase
276→        .from('follows')
277→        .insert(data)
278→
279→        if(errorInserData){
280→            console.error('supabase error while inserting follow data:', errorInserData.message);
281→            throw {status: 500, error: 'supabase error while inserting follow data:'}
282→        }
283→
284→        return {message: 'success'};
285→    }
286→}
