## Phase 5: Link Mode UI

### 5.1 New Hook for Constellation Link Mode

**File to create**: `C:\Users\johnm\iskrib_v3\client\src\components\Universe\hooks\useConstellationLinkMode.js`

```javascript
import { useState, useCallback, useRef } from 'react';
import { requestConstellation } from '../../../../API/Api';

export default function useConstellationLinkMode({ userId, session, onSuccess, onError }) {
    const [isLinkMode, setIsLinkMode] = useState(false);
    const [firstStar, setFirstStar] = useState(null); // { postId, userId, title }
    const [isSubmitting, setIsSubmitting] = useState(false);

    const toggleLinkMode = useCallback(() => {
        setIsLinkMode(prev => {
            if (prev) {
                // Exiting: reset selection
                setFirstStar(null);
            }
            return !prev;
        });
    }, []);

    const cancelLinkMode = useCallback(() => {
        setIsLinkMode(false);
        setFirstStar(null);
    }, []);

    const handleStarClickInLinkMode = useCallback(async (post) => {
        const postUserId = post.users?.id ?? post.user_id;

        if (!firstStar) {
            // First star selection - must be user's own star
            if (postUserId !== userId) {
                onError?.('Select one of YOUR stars first');
                return;
            }
            setFirstStar({ postId: post.id, userId: postUserId, title: post.title });
            return;
        }

        // Second star selection - must be a DIFFERENT user's star
        if (postUserId === userId) {
            onError?.('Second star must belong to another user');
            return;
        }

        // Send constellation request
        setIsSubmitting(true);
        try {
            const token = session?.access_token;
            await requestConstellation(token, firstStar.postId, post.id, '');
            onSuccess?.('Constellation request sent!');
            cancelLinkMode();
        } catch (err) {
            onError?.(err.message || 'Failed to send request');
        } finally {
            setIsSubmitting(false);
        }
    }, [firstStar, userId, session, cancelLinkMode, onSuccess, onError]);

    return {
        isLinkMode,
        firstStar,
        isSubmitting,
        toggleLinkMode,
        cancelLinkMode,
        handleStarClickInLinkMode,
    };
}
```

