## Phase 8: Multi-Star Chains

### 8.1 Chain Detection Algorithm

**File to create or add to**: `C:\Users\johnm\iskrib_v3\client\src\components\Universe\utils\constellationUtils.js`

```javascript
/**
 * Given an array of accepted constellations, compute connected components (chains).
 * Uses union-find for O(n * alpha(n)) performance.
 */
export const computeConstellationChains = (constellations) => {
    if (!Array.isArray(constellations) || constellations.length === 0) return [];

    // Union-Find
    const parent = new Map();
    const find = (x) => {
        if (!parent.has(x)) parent.set(x, x);
        if (parent.get(x) !== x) parent.set(x, find(parent.get(x)));
        return parent.get(x);
    };
    const union = (a, b) => {
        const ra = find(a);
        const rb = find(b);
        if (ra !== rb) parent.set(ra, rb);
    };

    // Build union-find from constellation edges
    for (const c of constellations) {
        union(c.star_id_a, c.star_id_b);
    }

    // Group by root
    const groups = new Map();
    for (const c of constellations) {
        const root = find(c.star_id_a);
        if (!groups.has(root)) groups.set(root, []);
        groups.get(root).push(c);
    }

    // Assign color family per chain
    let colorIndex = 0;
    const chains = [];
    for (const [root, links] of groups.entries()) {
        chains.push({
            id: root,
            links,
            colorIndex: colorIndex++,
            starIds: new Set(links.flatMap(l => [l.star_id_a, l.star_id_b])),
        });
    }

    return chains;
};

/**
 * Assign consistent color per chain to all links.
 * Links in the same chain share the same STAR_COLORS entry.
 */
export const assignChainColors = (chains, STAR_COLORS) => {
    const linkColorMap = new Map(); // constellationId -> color
    for (const chain of chains) {
        const color = STAR_COLORS[chain.colorIndex % STAR_COLORS.length];
        for (const link of chain.links) {
            linkColorMap.set(link.id, color);
        }
    }
    return linkColorMap;
};
```

